INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b6546218-357a-4be7-9c3a-5606fcdae979',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Feature Folders — Colocation, Barrel Exports, and Path Aliases Done Right$escape$,
  $escape$Feature-based folder structure in Angular groups a feature's component, service, model, pipe, and spec files into a single directory — the opposite of the type-based layout Angular CLI scaffolds by default.

A `users/` feature folder contains `user-list.component.ts`, `user.service.ts`, `user.model.ts`, and an `index.ts` barrel. The barrel defines the feature's public API: only explicitly exported symbols are accessible to the rest of the app. Consumers import from `@app/users`, never from deep internal paths like `../../users/user-list.component`.

Colocation makes refactoring cheap: moving or renaming a feature is a single folder operation. Angular's standalone component model (v15+) amplifies this — each feature manages its own dependency graph via `imports: []`, eliminating the `SharedModule` antipattern entirely.

Wire up path aliases in `tsconfig.json` to make barrel imports refactor-safe and IDE-navigable. Angular Language Service respects these aliases, so go-to-definition still works across the boundary.

Keep `index.ts` intentionally narrow — export only what other features need. Everything else stays private to the slice.$escape$,
  $escape$// src/app/users/index.ts — feature public API (barrel)
export { UserListComponent } from './user-list.component';
export { UserService } from './user.service';
export type { User } from './user.model';

// tsconfig.json
// "paths": { "@app/users": ["src/app/users/index.ts"] }

// Consuming feature — clean import, no leaking internals
import { UserListComponent, UserService } from '@app/users';

@Component({
  standalone: true,
  imports: [UserListComponent],
  template: `<app-user-list />`,
})
export class DashboardComponent {}$escape$,
  $escape$typescript$escape$,
