INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'aa7219fb-290c-48a4-8ba5-a0c5505d30d0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Data Fetching — Server State vs Client State with TanStack Query$escape$,
  $escape$Angular developers often conflate server state and client state — stuffing both into NgRx or a BehaviorSubject service. They're fundamentally different: server state is async, owned remotely, and can go stale; client state is synchronous, owned by your app, and always fresh.

TanStack Query's Angular adapter (@tanstack/angular-query-experimental) handles server state precisely. Use injectQuery() to declare a query bound to a key — it automatically caches, deduplicates, and background-refetches. Pair it with Angular signals: query.data() is a signal, so your template reacts without manual subscriptions or AsyncPipe gymnastics.

Client state — selected tab, modal open/closed, form draft — still belongs in component signals or a lightweight signal-based service. Don't route UI state through QueryClient.

Configure staleTime per query: 0 for real-time data, 60_000 for near-static lookups. Use placeholderData: keepPreviousData to avoid layout thrash on pagination. Call queryClient.invalidateQueries({ queryKey: ['users'] }) inside injectMutation's onSuccess to sync server and cache atomically — no manual refetch wiring needed.$escape$,
  $escape$import { injectQuery, injectMutation } from '@tanstack/angular-query-experimental';
import { inject } from '@angular/core';
import { UserService } from './user.service';

@Component({ standalone: true, template: `
  @if (query.isPending()) { <p>Loading...</p> }
  @if (query.isError()) { <p>Error: {{ query.error()?.message }}</p> }
  @for (user of query.data(); track user.id) { <li>{{ user.name }}</li> }
` })
export class UsersComponent {
  private userService = inject(UserService);

  query = injectQuery(() => ({
    queryKey: ['users'],
    queryFn: () => this.userService.getAll(),
    staleTime: 30_000,
  }));
}$escape$,
