INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f2898950-2e20-4a91-b7fd-40bc0209ed04',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Security: innerHTML Bypasses, Token Storage, and DomSanitizer$escape$,
  $escape$Angular's template engine auto-escapes interpolation (`{{ }}`), but `[innerHTML]` bindings are sanitized — not escaped. Angular strips dangerous tags like `<script>` and event handlers automatically via its built-in sanitizer. The trap is `bypassSecurityTrustHtml()` from `DomSanitizer`: calling it tells Angular to skip sanitization entirely, trusting your string as safe HTML. Only use it when rendering known-safe, server-controlled markup — never on user-supplied content.

For token storage, avoid `localStorage` for auth tokens — it's accessible to any JS on the page, making it XSS-vulnerable. Prefer `httpOnly` cookies (set server-side), which are inaccessible to JavaScript entirely. If you must use memory storage, keep tokens in a service-level variable, not a global.

For form inputs, Angular's `ReactiveFormsModule` doesn't sanitize values — that's your job. Validate with Validators and strip or encode before sending to APIs. Never interpolate raw form values into dynamic queries or HTML. Angular's `HttpClient` auto-encodes URL params, but body payloads are your responsibility.$escape$,
  $escape$// UNSAFE: bypasses Angular's sanitizer entirely
constructor(private sanitizer: DomSanitizer) {}

unsafeHtml(userInput: string): SafeHtml {
  return this.sanitizer.bypassSecurityTrustHtml(userInput); // ❌ never for user content
}

// SAFE: let Angular sanitize [innerHTML] normally
safeHtml(serverHtml: string): SafeHtml {
  // Angular strips <script>, onerror, etc. automatically
  return serverHtml; // bind with [innerHTML]="safeHtml(content)" ✅
}

// SAFE token storage: in-memory service, not localStorage
@Injectable({ providedIn: 'root' })
export class AuthTokenService {
  private token: string | null = null;
  setToken(t: string) { this.token = t; }
  getToken() { return this.token; }
}$escape$,
  $escape$typescript$escape$,
