INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '86300d62-b199-453c-a90c-f2a0751c4685',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Accessibility — Semantic HTML First, ARIA as Last Resort$escape$,
  $escape$Angular developers often reach for ARIA attributes prematurely. Start with semantic HTML — `<button>` over `<div (click)>`, `<nav>` over `<div class="nav">`. Angular's CDK provides `FocusTrap` and `LiveAnnouncer` for programmatic focus management that screen readers respect. Use `cdkTrapFocus` directive to contain focus inside modals, and inject `LiveAnnouncer` to announce dynamic content changes (e.g., after an HTTP call resolves). Only layer ARIA when native HTML semantics fall short — for example, a custom `ComboboxComponent` built from `<input>` + `<ul>` needs `role="combobox"`, `aria-expanded`, and `aria-activedescendant` because no native element maps to that pattern. Bind these dynamically with Angular's property binding (`[attr.aria-expanded]="isOpen"`), never hardcode them in the template. For route changes, Angular Router doesn't move focus automatically — use `Router.events` filtered to `NavigationEnd` to manually focus a skip-link or `<h1>` via `ViewChild` and `nativeElement.focus()`. Test with `axe-core` integrated into your Karma or Playwright suite.$escape$,
  $escape$// Focus management on route change
@Component({ selector: 'app-root', template: `
  <a #skipLink href="#main" class="sr-only">Skip to main</a>
  <main id="main" tabindex="-1" #mainContent>
    <router-outlet />
  </main>
` })
export class AppComponent {
  @ViewChild('mainContent') main!: ElementRef<HTMLElement>;

  constructor(router: Router) {
    router.events
      .pipe(filter(e => e instanceof NavigationEnd))
      .subscribe(() => this.main.nativeElement.focus());
  }
}$escape$,
  $escape$typescript$escape$,
