INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3be6685e-1961-4d0c-99b3-3fda9e1f0996',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular HTTP Layer — One HttpClient, Interceptors, Zero Raw Fetch$escape$,
  $escape$Angular's `HttpClient` is a singleton provided by `provideHttpClient()` — inject it once per service, never directly in components. Components own UI state; services own data fetching. Violating this makes interceptors blind to your requests.

Interceptors are where cross-cutting concerns live. Register them via `withInterceptors([authInterceptor, retryInterceptor])` (functional style, Angular 15+). An auth interceptor clones the outgoing request and attaches a Bearer token; a retry interceptor uses RxJS `retry({ count: 3, delay: 1000 })` to handle transient 5xx errors without duplicating that logic across 40 services.

Never call `fetch()` or `axios` in Angular — you lose the interceptor chain, zone.js change detection integration, and `HttpClientTestingModule` mock support. The `HttpContext` API lets interceptors communicate per-request (e.g. skip auth on public endpoints) without polluting headers. Keep interceptors pure and composable: one concern per interceptor, ordered intentionally at registration.$escape$,
  $escape$// auth.interceptor.ts
export const authInterceptor: HttpInterceptorFn = (req, next) => {
  const auth = inject(AuthService);
  const skip = req.context.get(SKIP_AUTH);
  if (skip || !auth.token()) return next(req);

  return next(req.clone({
    setHeaders: { Authorization: `Bearer ${auth.token()}` }
  }));
};

// retry.interceptor.ts
export const retryInterceptor: HttpInterceptorFn = (req, next) =>
  next(req).pipe(
    retry({ count: 3, delay: 1000 })
  );

// app.config.ts
provideHttpClient(withInterceptors([authInterceptor, retryInterceptor]))$escape$,
  $escape$typescript$escape$,
