INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5068cb2a-23ec-4b19-abcf-84364b3e2895',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Global UI Patterns — Toast, Modal, and Confirm as Injectable Services$escape$,
  $escape$Angular's global UI primitives — toasts, modals, confirmation dialogs — belong in singleton services, not scattered across component trees via `*ngIf` flags or `@ViewChild` hacks in `AppComponent`.

For toasts, use `ApplicationRef.attachView()` with `createComponent()` (Angular 14+) to mount a `ToastComponent` directly onto `document.body`. The component owns its own timer and calls `ApplicationRef.detachView()` on teardown — no parent needed.

For modals and confirm dialogs, Angular CDK `Overlay` is the idiomatic solution. Inject `Overlay`, call `overlay.create({ hasBackdrop: true })` to get an `OverlayRef`, then attach via `ComponentPortal`. Pass data and a result channel using a custom `Injector` built with `Injector.create()`. Expose a clean `open(message): Observable<boolean>` API from the service — callers subscribe and react declaratively.

This pattern keeps `AppComponent` pristine, makes dialogs testable in isolation, and avoids the `z-index` wars that come from portal-less approaches. All three patterns compose: a confirm dialog can itself trigger a toast on resolution.$escape$,
  $escape$@Injectable({ providedIn: 'root' })
export class ConfirmService {
  constructor(private overlay: Overlay, private injector: Injector) {}

  open(message: string): Observable<boolean> {
    const result$ = new Subject<boolean>();
    const ref = this.overlay.create({ hasBackdrop: true });
    const portal = new ComponentPortal(
      ConfirmDialogComponent, null,
      Injector.create({ providers: [
        { provide: CONFIRM_MESSAGE, useValue: message },
        { provide: CONFIRM_RESULT,  useValue: result$ }
      ], parent: this.injector })
    );
    ref.attach(portal);
    return result$.pipe(take(1), tap(() => ref.dispose()));
  }
}$escape$,
  $escape$typescript$escape$,
